mapper.select:
SELECT a.user_name username, a.id staffId, b.id, 'offline' status, a.user_photo avatar, IFNULL(a.user_sign, '暂无签名') sign, a.company_id companyId, a.department_id departmentId, a.job_id jobId FROM sys_eve_user_staff a, sys_eve_user b
,tenant_user k
WHERE a.user_id = b.id
#{departId}
AND a.id = k.staff_id AND k.tenant_id = #{tenantId} AND k.state != '2'
#{departId}
AND a.state != '2'
#{notInUserId}
ORDER BY convert(a.user_name using gbk) ASC
